  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The stars were diamonds in the sky." is an example of:', '["hyperbole","simile","personification","metaphor"]', 3, 'It calls one thing another — a metaphor.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"As quiet as a mouse." is an example of:', '["metaphor","personification","hyperbole","simile"]', 3, 'It compares using "like"/"as" — a simile.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"Time is a thief." is an example of:', '["metaphor","personification","simile","hyperbole"]', 0, 'It calls one thing another — a metaphor.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"She ran like the wind." is an example of:', '["metaphor","simile","personification","hyperbole"]', 1, 'It compares using "like"/"as" — a simile.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The sun smiled down on us." is an example of:', '["simile","personification","hyperbole","metaphor"]', 1, 'It gives human traits to a non-human thing — personification.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The wind whispered through the trees." is an example of:', '["metaphor","personification","hyperbole","simile"]', 1, 'It gives human traits to a non-human thing — personification.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The snow was a soft white blanket." is an example of:', '["hyperbole","metaphor","personification","simile"]', 1, 'It calls one thing another — a metaphor.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The flowers danced in the breeze." is an example of:', '["personification","metaphor","simile","hyperbole"]', 0, 'It gives human traits to a non-human thing — personification.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The classroom was a zoo." is an example of:', '["simile","hyperbole","personification","metaphor"]', 3, 'It calls one thing another — a metaphor.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"He was as busy as a bee." is an example of:', '["simile","hyperbole","personification","metaphor"]', 0, 'It compares using "like"/"as" — a simile.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"The thunder grumbled in the distance." is an example of:', '["personification","simile","hyperbole","metaphor"]', 0, 'It gives human traits to a non-human thing — personification.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', '"Her smile was as bright as the sun." is an example of:', '["metaphor","simile","personification","hyperbole"]', 1, 'It compares using "like"/"as" — a simile.', 15),
  ('reading', '4', 2, '4.theme', 'ELA.4.R.1', 'Read: "Even though the puzzle was hard, Jo kept trying. At last, the final piece clicked into place." What is the theme (lesson)?', '["Never give up","Winning is easy","Puzzles are boring","Always ask for help"]', 0, 'Jo kept trying until she finished — the lesson is to never give up.', 15),
  ('reading', '4', 3, '4.purpose', 'ELA.4.R.2', 'A writer lists reasons we should recycle and asks readers to start today. The author''s main purpose is to:', '["tell a joke","persuade","confuse","entertain"]', 1, 'Writing to convince the reader to do something is persuading.', 15),
  ('reading', '4', 2, '4.vocab', 'ELA.4.V.1', 'Read: "The fragile vase shattered the moment it slipped." The word "fragile" means:', '["colorful","strong","heavy","easily broken"]', 3, '"Fragile" means delicate and easily broken.', 15),
  ('science', '4', 2, '4.circuits', NULL, 'For a bulb to light in a simple circuit, the path must be ___.', '["painted","broken","wet","complete"]', 3, 'Electricity needs a complete (closed) path to flow.', 10),
  ('science', '4', 2, '4.circuits', NULL, 'What part stores the energy that makes a circuit work?', '["The battery","The wire alone","The air","The switch alone"]', 0, 'The battery supplies the energy for the circuit.', 10),
  ('science', '4', 2, '4.circuits', NULL, 'What part can open or close a circuit to turn it on or off?', '["A magnet","A bulb","A switch","A battery"]', 2, 'A switch opens or closes the circuit.', 10),
  ('science', '4', 2, '4.circuits', NULL, 'Materials that let electricity flow through them are called ___.', '["shadows","conductors","insulators","magnets"]', 1, 'Conductors, like metal, let electricity flow.', 10),
  ('science', '4', 2, '4.circuits', NULL, 'Which is a good conductor of electricity?', '["Plastic","Rubber","Metal wire","Dry wood"]', 2, 'Metals are good conductors of electricity.', 10),
  ('science', '4', 2, '4.circuits', NULL, 'If a wire in the circuit is broken, the bulb will ___.', '["change color","shine brighter","make sound","not light"]', 3, 'A broken path stops the electricity, so the bulb goes out.', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'Heat naturally moves from a ___ object to a ___ object.', '["in a circle forever","cooler object to a hotter one","hotter object to a cooler one","to no object"]', 2, 'Heat flows from hot to cold.', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'The sun''s energy travels to Earth as ___.', '["electricity in wires","light and heat","sound","wind"]', 1, 'The sun sends energy to Earth as light and heat.', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'A moving object has ___ energy.', '["sound only","motion (kinetic)","frozen","no"]', 1, 'Anything moving has energy of motion.', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'Plants change the sun''s light energy into ___.', '["electricity","stored food energy","wind","sound energy"]', 1, 'Plants store the sun''s energy as food (sugar).', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'When you turn on a lamp, electrical energy changes into ___.', '["only sound","rain","wind","light and heat"]', 3, 'A lamp turns electrical energy into light (and some heat).', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'Energy can change from one form to ___.', '["only sound","another","nothing","only light"]', 1, 'Energy can change forms, like electrical to light.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'The usual weather in a place over many years is called its ___.', '["a season only","a forecast","climate","a single storm"]', 2, 'Climate is the typical weather over a long time.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'Weather is what is happening ___.', '["right now","only in winter","only at night","over 100 years"]', 0, 'Weather is the conditions happening now or today.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'A place near the equator usually has a ___ climate.', '["snowy all year","warm","freezing","dark"]', 1, 'Places near the equator get strong sunlight and stay warm.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'Scientists who study the weather are called ___.', '["meteorologists","geologists","zookeepers","astronauts"]', 0, 'Meteorologists study and predict the weather.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'A tool that measures how much rain falls is a ___.', '["rain gauge","ruler for length","compass","thermometer"]', 0, 'A rain gauge collects and measures rainfall.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'Which sentence describes climate, not today''s weather?', '["It is usually hot and dry here.","It is cloudy this afternoon.","The wind is strong today.","It is raining right now."]', 0, 'Climate is the usual pattern; the others describe today.', 10),
  ('science', '4', 2, '4.moon', NULL, 'The moon seems to change shape because of how ___ lights it.', '["the stars","a streetlamp","the sun","the Earth"]', 2, 'We see the part of the moon lit by the sun, which changes.', 10),
  ('science', '4', 2, '4.moon', NULL, 'About how long does it take the moon to go through all its phases?', '["One hour","One day","One year","About a month"]', 3, 'The moon''s phases repeat about every 29–30 days.', 10),
  ('science', '4', 2, '4.moon', NULL, 'When we cannot see the lit moon at all, it is called a ___ moon.', '["blue","new","half","full"]', 1, 'At a new moon, the lit side faces away from us.', 10),
  ('science', '4', 2, '4.moon', NULL, 'When the whole lit side faces us, it is a ___ moon.', '["thin crescent","new","full","broken"]', 2, 'A full moon is when we see the entire lit side.', 10),
  ('science', '4', 2, '4.moon', NULL, 'The moon does not make its own light; it ___ the sun''s light.', '["reflects","swallows","creates","blocks"]', 0, 'The moon shines by reflecting sunlight.', 10),
  ('science', '4', 2, '4.moon', NULL, 'The moon moves around (orbits) the ___.', '["stars","Earth","Mars","Sun directly"]', 1, 'The moon orbits the Earth.', 10),
  ('science', '4', 2, '4.adaptations', NULL, 'A polar bear''s thick fur is an adaptation that helps it stay ___.', '["fast in water only","invisible","cool in the desert","warm"]', 3, 'Thick fur keeps the polar bear warm in the cold.', 10),
  ('science', '4', 2, '4.adaptations', NULL, 'A cactus stores ___ to survive in the dry desert.', '["rocks","sand","water","sunlight in a box"]', 2, 'A cactus stores water to live where it rarely rains.', 10),
  ('science', '4', 2, '4.adaptations', NULL, 'The shape of a bird''s beak helps it ___.', '["fly only","eat its kind of food","see at night","sing songs only"]', 1, 'Beak shapes are adapted to the foods birds eat.', 10),
  ('science', '4', 2, '4.adaptations', NULL, 'An adaptation is a feature that helps a living thing ___.', '["do homework","survive","get taller forever","stop eating"]', 1, 'Adaptations help living things survive in their habitat.', 10),
  ('science', '4', 2, '4.adaptations', NULL, 'A fish has gills that let it ___.', '["breathe in water","fly","walk on land","sleep standing"]', 0, 'Gills let fish take oxygen from water.', 10),
  ('science', '4', 2, '4.adaptations', NULL, 'A chameleon can change color to ___.', '["make light","hide from danger","get taller","freeze water"]', 1, 'Changing color helps a chameleon blend in (camouflage).', 10),
  ('science', '4', 2, '4.circuits', NULL, 'For a bulb to light up, the electric circuit must be ___.', '["wet","complete","broken","upside down"]', 1, 'Electricity needs a complete, unbroken path.', 10),
  ('science', '4', 2, '4.circuits', NULL, 'Which material lets electricity flow through it easily?', '["Plastic","Dry wood","Metal wire","Rubber"]', 2, 'Metals are good conductors of electricity.', 10),
  ('science', '4', 2, '4.energytransfer', NULL, 'Heat always moves from a ___ object to a cooler one.', '["cooler","lighter","warmer","heavier"]', 2, 'Heat flows from hot to cold.', 10),
  ('science', '4', 2, '4.weatherclimate', NULL, 'The usual weather pattern of a place over many years is its ___.', '["temperature today","season","climate","forecast"]', 2, 'Climate is the long-term pattern; weather is day to day.', 10),
  ('science', '4', 2, '4.moon', NULL, 'About how long does the moon take to go through all its phases?', '["About one day","About one week","About one year","About one month"]', 3, 'The moon cycles through its phases roughly every month.', 10),
