  ('reading', '5', 3, '5.fig', 'ELA.5.R.3', '"The snow was a soft white blanket." This is an example of:', '["metaphor","simile","personification","hyperbole"]', 0, 'Calling one thing another directly is a metaphor.', 15),
  ('reading', '5', 3, '5.fig', 'ELA.5.R.3', '"He was as busy as a bee." This is an example of:', '["personification","simile","metaphor","alliteration"]', 1, 'A comparison using "like" or "as" is a simile.', 15),
  ('reading', '5', 3, '5.fig', 'ELA.5.R.3', '"She ran like the wind." This is an example of:', '["simile","hyperbole","metaphor","personification"]', 0, 'A comparison using "like" or "as" is a simile.', 15),
  ('reading', '5', 3, '5.fig', 'ELA.5.R.3', '"The flowers danced in the breeze." This is an example of:', '["alliteration","simile","metaphor","personification"]', 3, 'Giving human actions to non-human things is personification.', 15),
  ('reading', '5', 3, '5.fig', 'ELA.5.R.3', '"Her smile was as bright as the sun." This is an example of:', '["personification","hyperbole","simile","metaphor"]', 2, 'A comparison using "like" or "as" is a simile.', 15),
